import{_ as a,o as n,c as t,ae as s}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":".NET Feature Implementation","description":"","frontmatter":{"title":".NET Feature Implementation","slug":"dotnet-feature-implementation"},"headers":[],"relativePath":"developer-hub/dotnet-feature-implementation.md","filePath":"developer-hub/dotnet-feature-implementation.md"}'),o={name:"developer-hub/dotnet-feature-implementation.md"};function r(i,e,p,c,l,h){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>While Branch configuration steps for <a href="./xamarin-configuration.html">Xamarin</a> and <a href="./maui-configuration.html">MAUI</a> applications differ, both types of applications use the same set of Branch SDK methods for feature implementation. These methods can be used to support both the iOS and Android components of your .NET application.</p><p><strong>IMPORTANT</strong>: Please note that both Xamarin and MAUI applications need to use the <code>Branch-Xamarin-Linking-SDK</code> NuGet package, but that versions 9.0.0+ are only for MAUI apps. Earlier versions are for Xamarin.</p><h2 id="deep-link" tabindex="-1">Deep Link <a class="header-anchor" href="#deep-link" aria-label="Permalink to &quot;Deep Link&quot;">​</a></h2><p>The Branch SDK has a collection of methods that make creating, sharing, and reading Branch Deep Links simple.</p><h3 id="create-content-reference" tabindex="-1">Create Content Reference <a class="header-anchor" href="#create-content-reference" aria-label="Permalink to &quot;Create Content Reference&quot;">​</a></h3><p>The <code>BranchUniversalObject</code> (<a href="./create-branch-objects-and-events.html">BUO</a>) class is a central concept in Branch event tracking and logging. You can create a BUO instance and fill in its <a href="./create-branch-objects-and-events.html#buo-properties">properties</a> in the following way:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchUniversalObject buo = new BranchUniversalObject();</span></span>
<span class="line"><span>buo.canonicalIdentifier = &quot;id12345&quot;;</span></span>
<span class="line"><span>buo.title = &quot;id12345 title&quot;;</span></span>
<span class="line"><span>buo.contentDescription = &quot;My awesome piece of content!&quot;;</span></span>
<span class="line"><span>buo.imageUrl = &quot;https://example.com/image.png&quot;;</span></span>
<span class="line"><span>buo.metadata.AddCustomMetadata(&quot;foo&quot;, &quot;bar&quot;);</span></span></code></pre></div><h3 id="create-deep-link" tabindex="-1">Create Deep Link <a class="header-anchor" href="#create-deep-link" aria-label="Permalink to &quot;Create Deep Link&quot;">​</a></h3><p>To create a Branch Deep Link, start by creating a <a href="./create-branch-objects-and-events.html#deep-link-data-structure">link properties</a> object with <code>new BranchLinkProperties();</code> and adding relevant data to it. Then pass that object, as well as a <a href="./dotnet-feature-implementation.html#create-content-reference">BUO instance</a>, to the <code>GetShortUrl()</code> method to actually create the link.</p><p>You can verify Branch Deep Link creation in the <strong>Liveview</strong> section of the Branch <a href="https://dashboard.branch.io/liveview" target="_blank" rel="noreferrer">Dashboard</a>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchLinkProperties linkProperties = new BranchLinkProperties();</span></span>
<span class="line"><span>linkProperties.tags.Add(&quot;tag1&quot;);</span></span>
<span class="line"><span>linkProperties.tags.Add(&quot;tag2&quot;);</span></span>
<span class="line"><span>linkProperties.feature = &quot;sharing&quot;;</span></span>
<span class="line"><span>linkProperties.channel = &quot;facebook&quot;;</span></span>
<span class="line"><span>linkProperties.controlParams.Add(&quot;$desktop_url&quot;, &quot;http://example.com&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Branch.GetInstance().GetShortURL(callback,</span></span>
<span class="line"><span>                                  universalObject,</span></span>
<span class="line"><span>                                  linkProperties);</span></span></code></pre></div><h3 id="share-deep-link" tabindex="-1">Share Deep Link <a class="header-anchor" href="#share-deep-link" aria-label="Permalink to &quot;Share Deep Link&quot;">​</a></h3><p>The <code>ShareLink()</code> method will generate a Branch Deep Link and tag it with the channel the user selects. You will need to pass this method a <a href="./dotnet-feature-implementation.html#create-content-reference">BUO instance</a> and a <a href="./dotnet-feature-implementation.html#create-deep-link">link properties object</a>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch.GetInstance().ShareLink (callback,</span></span>
<span class="line"><span>           universalObject,</span></span>
<span class="line"><span>           linkProperties,</span></span>
<span class="line"><span>           message)</span></span></code></pre></div><h3 id="read-deep-link" tabindex="-1">Read Deep Link <a class="header-anchor" href="#read-deep-link" aria-label="Permalink to &quot;Read Deep Link&quot;">​</a></h3><p>Reading a Branch Deep Link means retrieving <a href="./dotnet-feature-implementation.html#create-deep-link">properties</a> about that specific Deep Link.</p><p>Please note that Branch recommends receiving data from the listener to prevent a race condition.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Get the parameters used the most recent time this user was referred</span></span>
<span class="line"><span>Dictionary&lt;string, object&gt; sessionParams = Branch.GetInstance().GetLastReferringParams();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Get the parameters used the first time this user was referred</span></span>
<span class="line"><span>Dictionary&lt;string, object&gt; installParams = Branch.GetInstance().GetFirstReferringParams();</span></span></code></pre></div><h3 id="deferred-deep-linking" tabindex="-1">Deferred Deep Linking <a class="header-anchor" href="#deferred-deep-linking" aria-label="Permalink to &quot;Deferred Deep Linking&quot;">​</a></h3><p>Use the iOS pasteboard to enable deferred deep linking via Branch NativeLink™.</p><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p><strong>Make sure you are on</strong> <a href="https://github.com/BranchMetrics/xamarin-branch-deep-linking-attribution/releases/tag/7.1.2" target="_blank" rel="noreferrer"><strong>v7.1.2+</strong></a></p><p>To use this feature you must:</p><ul><li><a href="./configure-default-link-behaviors.html#3-ios-default-link-behavior">Enable NativeLink™ Deep Linking</a> in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Branch Dashboard Configuration tab</a><br><strong>or</strong></li><li>Manually configure your Branch Link to use <a href="./creating-a-deep-link.html#deep-linking">$ios_nativelink</a></li></ul></div><p>To use the iOS pasteboard, implement one of the <a href="./ios-advanced-features.html#implementation-options">pasteboard opt-in options</a>.</p><h2 id="track-events" tabindex="-1">Track Events <a class="header-anchor" href="#track-events" aria-label="Permalink to &quot;Track Events&quot;">​</a></h2><p>Branch SDK event tracking methods allow you to log <a href="./create-branch-objects-and-events.html#branch-event">events</a> that take place in your app.</p><p>Before tracking events with Branch, you&#39;ll want to familiarize yourself with the concept of a <a href="./create-branch-objects-and-events.html#branch-universal-object">Branch Universal Object</a> (BUO).</p><p>You can use the Branch <a href="https://branch.dashboard.branch.io/liveview/events" target="_blank" rel="noreferrer">Dashboard</a> to verify that your Branch Events are being captured correctly.</p><h3 id="track-commerce-events" tabindex="-1">Track Commerce Events <a class="header-anchor" href="#track-commerce-events" aria-label="Permalink to &quot;Track Commerce Events&quot;">​</a></h3><p>Commerce events describe events that relate to a customer interacting with your products and whether those interactions convert to a purchase. That conversion would be represented by a <code>PURCHASE</code> event. Other commerce events include things like adding payment information and viewing products.</p><p>You can track commerce event by creating a BUO for each product that is associated with the event you&#39;re tracking.</p><p>From there, add the BUO to the tracked event with <code>AddContentItem</code>, and use the right predefined <code>BranchEventType</code> for the event you want to track:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchUniversalObject buo = new BranchUniversalObject();</span></span>
<span class="line"><span>buo.canonicalIdentifier = &quot;id12345&quot;;</span></span>
<span class="line"><span>buo.canonicalUrl = &quot;https://branch.io/item/id12345&quot;;</span></span>
<span class="line"><span>buo.title = &quot;Item 12345&quot;;</span></span>
<span class="line"><span>buo.contentDescription = &quot;My awesome piece of content!&quot;;</span></span>
<span class="line"><span>buo.imageUrl = &quot;https://example.com/image.png&quot;;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>buo.metadata.price = (float)23.20;</span></span>
<span class="line"><span>buo.metadata.quantity = 1;</span></span>
<span class="line"><span>buo.metadata.sku = &quot;1994329302&quot;;</span></span>
<span class="line"><span>buo.metadata.productName = &quot;my_product_name1&quot;;</span></span>
<span class="line"><span>buo.metadata.productBrand = &quot;my_product_brand1&quot;;</span></span>
<span class="line"><span>buo.metadata.productCategory = 				        BranchProductCategory.APPAREL_AND_ACCESSORIES;</span></span>
<span class="line"><span>buo.metadata.productVariant = &quot;XL&quot;;</span></span>
<span class="line"><span>buo.metadata.condition = BranchCondition.NEW;</span></span>
<span class="line"><span>buo.metadata.AddCustomMetadata(&quot;foo&quot;, &quot;bar&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>BranchEvent branchCommerceEvent = new BranchEvent(BranchEventType.PURCHASE);</span></span>
<span class="line"><span>branchCommerceEvent.SetAlias(&quot;new_user_purchase&quot;);</span></span>
<span class="line"><span>branchCommerceEvent.AddContentItem(buo); </span></span>
<span class="line"><span>branchCommerceEvent.SetRevenue((float)1.5);</span></span>
<span class="line"><span>branchCommerceEvent.SetShipping((float)10.5);</span></span>
<span class="line"><span>branchCommerceEvent.SetCurrency(BranchCurrencyType.USD);</span></span>
<span class="line"><span>branchCommerceEvent.SetTax((float)12.3);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Branch.GetInstance().SendEvent(branchCommerceEvent);</span></span></code></pre></div><h3 id="track-content-events" tabindex="-1">Track Content Events <a class="header-anchor" href="#track-content-events" aria-label="Permalink to &quot;Track Content Events&quot;">​</a></h3><p>Content events occur when a user engages with your in-app content. This includes user searches, content viewing, content rating, and sharing. This can apply to a wide variety of in-app content, such as blog posts, music, videos, pictures, and e-commerce catalogue items.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchEvent branchContentEvent = new BranchEvent(BranchEventType.SEARCH);</span></span>
<span class="line"><span>branchContentEvent.SetAlias(&quot;my_custom_alias&quot;);</span></span>
<span class="line"><span>branchContentEvent.SetDescription(&quot;Product Search&quot;);</span></span>
<span class="line"><span>branchContentEvent.SetSearchQuery(&quot;user search query terms for product xyz&quot;);</span></span>
<span class="line"><span>branchContentEvent.AddCustomData(&quot;content_event_property_key1&quot;, &quot;content_event_property_val1&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Branch.GetInstance().SendEvent(branchContentEvent);</span></span></code></pre></div><h3 id="track-lifecycle-events" tabindex="-1">Track Lifecycle Events <a class="header-anchor" href="#track-lifecycle-events" aria-label="Permalink to &quot;Track Lifecycle Events&quot;">​</a></h3><p>Lifecycle events represent actions the user takes in your app to continue progressing through it. These events can apply to game apps as well as non-game apps, and includes actions like a user completing a profile, registering for something, or going through a tutorial.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchEvent branchLifecycleEvent = new BranchEvent(BranchEventType.COMPLETE_REGISTRATION);</span></span>
<span class="line"><span>branchLifecycleEvent.SetAlias(&quot;registration_flow_xyz&quot;); branchLifecycleEvent.SetDescription(&quot;Existing User Registration&quot;);</span></span>
<span class="line"><span>branchLifecycleEvent.AddCustomData(&quot;lifeycle_event_property_key1&quot;, &quot;lifecycle_event_property_val1&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Branch.GetInstance().SendEvent(branchLifecycleEvent);</span></span></code></pre></div><h3 id="track-custom-events" tabindex="-1">Track Custom Events <a class="header-anchor" href="#track-custom-events" aria-label="Permalink to &quot;Track Custom Events&quot;">​</a></h3><p>If you want to track an event that isn&#39;t predefined, you have the option to create a custom event.</p><p><strong>Important</strong>: Branch strongly recommends using custom event names that contain no more than 40 characters, contain only letters, numbers, hyphens, spaces and underscores, and do not start with a hyphen.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchEvent branchCustomEvent = new BranchEvent(&quot;custom_event&quot;);</span></span>
<span class="line"><span>branchCustomEvent.SetAlias(&quot;custom_event_alias&quot;);</span></span>
<span class="line"><span>branchCustomEvent.SetDescription(&quot;Custom Event Description&quot;);</span></span>
<span class="line"><span>branchCustomEvent.AddCustomData(&quot;custom_event_property_key1&quot;, &quot;custom_event_property_val1&quot;);</span></span>
<span class="line"><span>branchCustomEvent.AddCustomData(&quot;custom_event_property_key2&quot;, &quot;custom_event_property_val2&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Branch.GetInstance().SendEvent(branchCustomEvent);</span></span></code></pre></div><h2 id="set-user-tracking" tabindex="-1">Set User Tracking <a class="header-anchor" href="#set-user-tracking" aria-label="Permalink to &quot;Set User Tracking&quot;">​</a></h2><p>You can set the identity of a user with the <code>SetIdentity()</code> method. This method sets the identity of a user (ID, UUID, etc.) for events, deep links, and referrals.</p><p>You can validate that user identities are being set properly using the Branch <a href="https://dashboard.branch.io/liveview/identities" target="_blank" rel="noreferrer">Dashboard</a>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch branch = Branch.GetInstance ();</span></span>
<span class="line"><span>branch.SetIdentity(&quot;the user id&quot;, this);  // Where this implements IBranchIdentityInterface</span></span>
<span class="line"><span>branch.Logout(this); // Where this implements IBranchIdentityInterface</span></span></code></pre></div><h2 id="troubleshoot" tabindex="-1">Troubleshoot <a class="header-anchor" href="#troubleshoot" aria-label="Permalink to &quot;Troubleshoot&quot;">​</a></h2><h4 id="xamarin-troubleshooting" tabindex="-1">Xamarin: <a href="./xamarin-configuration.html#troubleshoot">Troubleshooting</a> <a class="header-anchor" href="#xamarin-troubleshooting" aria-label="Permalink to &quot;Xamarin: [Troubleshooting](xamarin-configuration.md#troubleshoot)&quot;">​</a></h4><h4 id="maui-troubleshooting" tabindex="-1">MAUI: <a href="./maui-configuration.html#6-troubleshoot">Troubleshooting</a> <a class="header-anchor" href="#maui-troubleshooting" aria-label="Permalink to &quot;MAUI: [Troubleshooting](maui-configuration.md#6-troubleshoot)&quot;">​</a></h4>`,49)])])}const m=a(o,[["render",r]]);export{d as __pageData,m as default};
